// Extract and parse the AI output text
let rawText = items[0].json.content?.parts?.[0]?.text;

// Remove Markdown code block if present
if (rawText) {
  rawText = rawText.replace(/^\s*```(?:json)?\s*([\s\S]*?)\s*```\s*$/im, '$1').trim();
}

if (!rawText) {
  throw new Error("No text content found in AI output.");
}

// Parse JSON string from AI
let parsed;
try {
  parsed = JSON.parse(rawText);
} catch (err) {
  throw new Error(`Failed to parse JSON from AI output: ${err.message}`);
}

// Extract fields
const doctorName = parsed.Doctor_Name;
const startTimeRaw = parsed.Start_Time;
const endTimeRaw = parsed.End_Time;

// Validate fields
if (!startTimeRaw || !endTimeRaw) {
  throw new Error(`Missing Start_Time or End_Time. Got: Start_Time=${startTimeRaw}, End_Time=${endTimeRaw}`);
}

// Convert to Date objects
const startTime = new Date(startTimeRaw);
const endTime = new Date(endTimeRaw);

// Check validity
if (isNaN(startTime.getTime()) || isNaN(endTime.getTime())) {
  throw new Error(`Invalid Start_Time or End_Time. Start_Time: ${startTimeRaw}, End_Time: ${endTimeRaw}`);
}

// Return in proper ISO format
return [{
  json: {
    Doctor_Name: doctorName,
    Start_Time: startTime.toISOString(),
    End_Time: endTime.toISOString()
  }
}];

const output = [];

for (const item of $input.all()) {
  // If appointment is not available or missing start time
  if (!item.json.Start_Time) {
    // Suggest next 3 hourly slots from current time
    const now = new Date();
    const suggestions = [];

    for (let i = 1; i <= 3; i++) {
      const next = new Date(now.getTime() + i * 60 * 60 * 1000);
      suggestions.push(next.toISOString());
    }

    output.push({ json: { available: false, suggestions } });
  } else {
    // Appointment exists, suggest next 3 slots after current start time
    const baseTime = new Date(item.json.Start_Time);
    const suggestions = [];

    for (let i = 1; i <= 3; i++) {
      const next = new Date(baseTime.getTime() + i * 60 * 60 * 1000);
      suggestions.push(next.toISOString());
    }

    output.push({ json: { available: true, suggestions } });
  }
}

return output;

