const raw = $json.output || "";

function find_all_functions(text) {
  const res = [];
  let idx = 0;
  while (true) {
    const fn_start = text.indexOf("<function=", idx);
    if (fn_start === -1) break;
    const fn_name_start = fn_start + 10;
    const fn_name_end = text.indexOf(">", fn_name_start);
    if (fn_name_end === -1) break;
    const fn_name = text.substring(fn_name_start, fn_name_end);
    const json_start = fn_name_end + 1;
    let brace_open = text.indexOf("{", json_start);
    let brace_close = -1;
    let depth = 0;
    for (let i = brace_open; i < text.length; i++) {
      if (text[i] === "{") depth++;
      if (text[i] === "}") depth--;
      if (depth === 0) {
        brace_close = i;
        break;
      }
    }
    if (brace_open !== -1 && brace_close !== -1) {
      res.push([fn_name, text.substring(brace_open, brace_close + 1)]);
      idx = brace_close + 1;
    } else break;
  }
  return res;
}

function get_value(s, key) {
  const regex = new RegExp(`"${key}"\\s*:\\s*"([^"]+)"`);
  const match = s.match(regex);
  return match ? match[1] : "";
}

function format_time_readable(iso_str) {
  if (iso_str.length >= 16 && iso_str[4] === "-" && iso_str[7] === "-") {
    const [date, time] = iso_str.split("T");
    const [y, m, d] = date.split("-");
    const timePart = time ? time.slice(0, 5) : "00:00";
    let [hour, minute] = timePart.split(":");
    hour = parseInt(hour);
    const ampm = hour < 12 ? "AM" : "PM";
    const h12 = hour === 0 ? 12 : hour > 12 ? hour - 12 : hour;
    const months = [
      "January", "February", "March", "April", "May", "June",
      "July", "August", "September", "October", "November", "December"
    ];
    const mon_name = months[parseInt(m) - 1] || m;
    return `${d} ${mon_name} at ${h12}:${minute} ${ampm}`;
  }
  return iso_str;
}

let clean_message = "";
const plain_text_part = raw.split("<function=")[0].trim();
if (plain_text_part) clean_message += plain_text_part + "\n";

const matches = find_all_functions(raw);
for (const [tool_name, json_str] of matches) {
