    const start = format_time_readable(
      get_value(json_str, "Start") || get_value(json_str, "Start_Time")
    );
    const end = format_time_readable(
      get_value(json_str, "End") || get_value(json_str, "End_Time")
    );
    const summary = get_value(json_str, "Summary") || "an appointment";
    const doctor = summary.replace("Appointment with ", "");
